const fs = require('fs');
const path = require('path');

const sanitize = (s, max = 120) => {
  let v = String(s == null ? '' : s);
  v = v.replace(/[<>:"/\\|?*\x00-\x1f]/g, '_');
  v = v.replace(/\s+/g, ' ').trim();
  if (!v) v = 'untitled';
  return v.slice(0, max);
};

// 소유자 폴더명 규칙:
//  1) project.name 안에 <email> 이 있으면 email local part 사용 (예: inyoung.lee)
//  2) 그 외엔 sanitize 된 이름
//  3) 둘 다 없으면 'unknown'
const ownerSlug = (projectName) => {
  if (!projectName) return 'unknown';
  const m = String(projectName).match(/<([^>@\s]+)@[^>]+>/);
  if (m) return sanitize(m[1], 64);
  return sanitize(projectName, 64);
};

const BASE = '/backups';
const results = [];

for (const item of $input.all()) {
  const wf = item.json;
  const projectName = wf.shared && wf.shared[0] && wf.shared[0].project && wf.shared[0].project.name;
  const owner = ownerSlug(projectName);
  const safeName = sanitize(wf.name, 120);
  const dirPath = path.join(BASE, owner);
  const fileName = safeName + '__' + wf.id + '.json';
  const filePath = path.join(dirPath, fileName);

  fs.mkdirSync(dirPath, { recursive: true });
  fs.writeFileSync(filePath, JSON.stringify(wf, null, 2), 'utf8');

  results.push({ json: { id: wf.id, name: wf.name, owner, filePath } });
}

return results;

const fs = require('fs');
const path = require('path');

const TOKEN = $env.GITHUB_TOKEN;
const OWNER = $env.GITHUB_BACKUP_OWNER;
const REPO = $env.GITHUB_BACKUP_REPO;
const BRANCH = $env.GITHUB_BACKUP_BRANCH;
const BASE = '/backups';

if (!TOKEN || !OWNER || !REPO || !BRANCH) {
  throw new Error('Missing GITHUB_* env vars on n8n container');
}

const gh = (method, urlPath, body) => $helpers.httpRequest({
  method,
  url: 'https://api.github.com' + urlPath,
  headers: {
    'Authorization': 'Bearer ' + TOKEN,
    'Accept': 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28',
    'User-Agent': 'n8n-workflow-backup',
  },
  body,
  json: true,
});

function walk(dir, base) {
  const out = [];
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, ent.name);
    if (ent.isDirectory()) out.push(...walk(full, base));
    else if (ent.isFile() && ent.name.endsWith('.json')) {
      out.push({
        path: path.relative(base, full).split(path.sep).join('/'),
        content: fs.readFileSync(full, 'utf8'),
      });
    }
  }
  return out;
}

const files = walk(BASE, BASE);
if (files.length === 0) {
  return [{ json: { committed: false, reason: 'no files' } }];
}

// repo는 README.md 부트스트랩되어 있어 항상 ref/commit이 존재한다는 가정
const ref = await gh('GET', `/repos/${OWNER}/${REPO}/git/ref/heads/${BRANCH}`);
const currentCommitSha = ref.object.sha;
const cur = await gh('GET', `/repos/${OWNER}/${REPO}/git/commits/${currentCommitSha}`);
const baseTreeSha = cur.tree.sha;

const tree = files.map(f => ({ path: f.path, mode: '100644', type: 'blob', content: f.content }));
const newTree = await gh('POST', `/repos/${OWNER}/${REPO}/git/trees`, { base_tree: baseTreeSha, tree });

if (newTree.sha === baseTreeSha) {
  return [{ json: { committed: false, reason: 'no changes', fileCount: files.length } }];
}

const today = new Date().toLocaleDateString('sv-SE', { timeZone: 'Asia/Seoul' });
const commit = await gh('POST', `/repos/${OWNER}/${REPO}/git/commits`, {
  message: `n8n workflow backup ${today} (${files.length} files)`,
  tree: newTree.sha,
  parents: [currentCommitSha],
});

await gh('PATCH', `/repos/${OWNER}/${REPO}/git/refs/heads/${BRANCH}`, { sha: commit.sha });

return [{ json: { committed: true, commitSha: commit.sha, fileCount: files.length, message: commit.message } }];

